class SafeReactAgent:
    def __init__(self, tools):
        self.tools = {tool.metadata.name: tool for tool in tools}

    def safe_query(self, query):
        agent_response = self.agent.chat(query)
        tool_calls = agent_response.tool_calls or []

        for call in tool_calls:
            if call.name not in self.tools:
                raise ValueError(f'Unauthorized tool call: {call.name}')
        return agent_response

